SELECT ${params.xColumn}, IFNULL(
ROUND(sum(${params.yColumn}), 2) ROUND(count(${params.yColumn}), 2) ROUND(max(${params.yColumn}), 2) ROUND(min(${params.yColumn}), 2) ROUND(avg(${params.yColumn}), 2) sum(${params.yColumn})
, 0) total FROM qiantuijilu 1=1 ${ew.sqlSegment} group by ${params.xColumn}
order by ${params.xColumn} ${params.order}
order by total ${params.order}

